//! Database seeder binary for module: support
//!
//! Generated by metaphor-schema. Do not edit manually.
//!
//! Run with: cargo run --bin support-seeder
//! Or via CLI: backbone seed run --module support
//!
//! This binary runs all registered seeders in order.

use anyhow::Result;
use sqlx::postgres::PgPoolOptions;
use std::env;

// Import seeders
use backbone_support::seeders::SeedIssueSeeder;
use backbone_support::seeders::SeedServiceLevelAgreementSeeder;
use backbone_support::seeders::SeedServiceLevelPrioritySeeder;
use backbone_support::seeders::SeedWarrantyClaimSeeder;
use backbone_support::seeders::Seeder;

#[tokio::main]
async fn main() -> Result<()> {
    let args: Vec<String> = env::args().collect();
    let force = args.iter().any(|a| a == "--force");
    let filter: Option<&str> = args.iter()
        .skip(1)
        .find(|a| !a.starts_with("-"))
        .map(|s| s.as_str());

    let database_url = env::var("DATABASE_URL")
        .expect("DATABASE_URL must be set");

    println!("Connecting to database...");

    let pool = PgPoolOptions::new()
        .max_connections(5)
        .connect(&database_url)
        .await?;

    println!("Connected to database");
    println!();
    println!("Running seeders for module: support");
    println!();

    // Register seeders in order
    let mut seeders: Vec<Box<dyn Seeder + Send + Sync>> = Vec::new();
    seeders.push(Box::new(SeedIssueSeeder::new()));
    seeders.push(Box::new(SeedServiceLevelAgreementSeeder::new()));
    seeders.push(Box::new(SeedServiceLevelPrioritySeeder::new()));
    seeders.push(Box::new(SeedWarrantyClaimSeeder::new()));

    // Sort by order
    seeders.sort_by_key(|s| s.order());

    // Run seeders
    for seeder in &seeders {
        let name = seeder.name();

        // Apply filter if specified
        if let Some(f) = filter {
            if !name.contains(f) {
                continue;
            }
        }

        if force {
            println!("   Running {}...", name);
            seeder.run(&pool).await?;
            println!("   {} completed", name);
        } else {
            println!("   Checking {}...", name);
            if seeder.should_run(&pool).await? {
                println!("   Running {}...", name);
                seeder.run(&pool).await?;
                println!("   {} completed", name);
            } else {
                println!("   {} already applied, skipping", name);
            }
        }
    }

    println!();
    println!("All seeders completed successfully!");

    Ok(())
}
